import Ticket from "../images/ticket.jpg";
const Home = () => {
  return (
    <div className="text-center">
      <h2>Find a movie to watch tonight!</h2>
      <hr />
      <img src={Ticket} alt="movie ticket"></img>
    </div>
  );
};

export default Home;
